import{_ as e,c as t,o as r,d as a}from"./app.1c033fc5.js";const g='{"title":"\u0427\u0435\u0442\u044B\u0440\u0435 \u0444\u0430\u0437\u044B","description":"","frontmatter":{"title":"\u0427\u0435\u0442\u044B\u0440\u0435 \u0444\u0430\u0437\u044B","subtitle":"\u0421\u0442\u043E\u0440\u043E\u043D\u044B \u0441\u0432\u0435\u0442\u0430 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043A\u043E\u043C\u043F\u0430\u0441\u0430","date":"2017-01-02T00:00:00.000Z","icon":"four.svg","color":"#EBDC6133"},"headers":[{"level":2,"title":"\u0426\u0438\u043A\u043B \u041D\u041E\u0420\u0414","slug":"\u0446\u0438\u043An-\u043D\u043E\u0440\u0434"},{"level":3,"title":"\u041A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F \u041D\u041E\u0420\u0414","slug":"\u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F-\u043D\u043E\u0440\u0434"},{"level":3,"title":"4 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430 \u041D\u041E\u0420\u0414","slug":"_4-\u044Dn\u0435\u043C\u0435\u043D\u0442\u0430-\u043D\u043E\u0440\u0434"},{"level":3,"title":"\u0426\u0438\u043A\u043B \u041D\u041E\u0420\u0414 \u0432 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0435","slug":"\u0446\u0438\u043An-\u043D\u043E\u0440\u0434-\u0432-\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0435"}],"relativePath":"theory/system/projectapp/four/index.md"}',n={},i=a('<p>\u0420\u0430\u0437\u0431\u0438\u0435\u043D\u0438\u0435 \u0446\u0438\u043A\u043B\u0430 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430 \u043D\u0430 4 \u0444\u0430\u0437\u044B \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 \u0434\u043B\u044F \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0445 \u043D\u0430\u0447\u0438\u043D\u0430\u043D\u0438\u0439 \u0438 \u0431\u044B\u0441\u0442\u0440\u044B\u0445 \u0438\u0442\u0435\u0440\u0430\u0446\u0438\u0439. \u042D\u0442\u043E \u0430\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u043E \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u0431\u044B\u0441\u0442\u0440\u043E \u043C\u0435\u043D\u044F\u044E\u0449\u0438\u0445\u0441\u044F \u0443\u0441\u043B\u043E\u0432\u0438\u0439 \u0438\u043B\u0438 \u043A\u043E\u0433\u0434\u0430 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442 \u0431\u043E\u043B\u044C\u0448\u0438\u0439 \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442, \u0447\u0435\u043C \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0438\u0445 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F.</p><p>\u041A\u0430\u043A \u0432\u0440\u0435\u043C\u0435\u043D\u0430 \u0433\u043E\u0434\u0430 \u0441\u043C\u0435\u043D\u044F\u044E\u0442\u0441\u044F \u0444\u0430\u0437\u044B \u043F\u0440\u0438\u0434\u0443\u043C\u044B\u0432\u0430\u043D\u0438\u044F, \u043F\u0440\u043E\u0440\u0430\u0431\u043E\u0442\u043A\u0438, \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u043E\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u0438\u044F \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0430. \u0415\u0441\u043B\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0442\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0435 \u043E\u0442 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0431\u0440\u0430\u0437\u0430 \u0438\u0434\u0435\u0438, \u0430 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u043E\u0442 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0443\u0441\u043B\u043E\u0432\u0438\u0439, \u0442\u043E \u044D\u0442\u043E\u0442 \u043A\u0440\u0443\u0433 \u043F\u043E\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0430 45 \u0433\u0440\u0430\u0434\u0443\u0441\u043E\u0432 \u043F\u043E \u0447\u0430\u0441\u043E\u0432\u043E\u0439 \u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C \u0441 1995 \u0433\u043E\u0434\u0430 <a href="https://ru.wikipedia.org/wiki/%D0%A6%D0%B8%D0%BA%D0%BB_%D0%9D%D0%9E%D0%A0%D0%94" class="external-link" target="_blank" rel="noopener noreferrer">\u0446\u0438\u043A\u043B\u043E\u043C \u041D\u041E\u0420\u0414</a>.</p><h2 id="\u0446\u0438\u043An-\u043D\u043E\u0440\u0434" tabindex="-1">\u0426\u0438\u043A\u043B \u041D\u041E\u0420\u0414 <a class="header-anchor" href="#\u0446\u0438\u043An-\u043D\u043E\u0440\u0434" aria-hidden="true">#</a></h2><p>\u0426\u0438\u043A\u043B \u041D\u041E\u0420\u0414 (\xAB\u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0435, \u043E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u044F, \u0440\u0435\u0448\u0435\u043D\u0438\u0435, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\xBB) \u2014 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u0430\u044F \u0414\u0436\u043E\u043D\u043E\u043C \u0411\u043E\u0439\u0434\u043E\u043C \u0432 1995 \u0433\u043E\u0434\u0443, \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A \xAB\u043F\u0435\u0442\u043B\u044F \u0411\u043E\u0439\u0434\u0430\xBB. \u041D\u041E\u0420\u0414 \u2014 \u044D\u0442\u043E \u043A\u0438\u0431\u0435\u0440\u043D\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0441\u0430\u043C\u043E\u0432\u043E\u0441\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F\u0449\u0438\u0439\u0441\u044F \u0438 \u0441\u0430\u043C\u043E\u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u044E\u0449\u0438\u0439\u0441\u044F \u0446\u0438\u043A\u043B, \u0438\u043C\u0435\u044E\u0449\u0438\u0439 \u0432 \u0441\u0432\u043E\u0435\u0439 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0435 4 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u0438 \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u0430\u0433\u0430\u0435\u0442 \u043C\u043D\u043E\u0433\u043E\u043A\u0440\u0430\u0442\u043D\u043E\u0435 \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u0435 \u043F\u0435\u0442\u043B\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439: \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u0439 \u0441\u0432\u044F\u0437\u0438. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0411\u043E\u0439\u0434\u0443, \u043B\u044E\u0431\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u0432 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C \u0446\u0438\u043A\u043B\u0435, \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u0441 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0439 \u0441\u0440\u0435\u0434\u043E\u0439 \u0438 \u0443\u0447\u0438\u0442\u044B\u0432\u0430\u044E\u0442 \u0435\u0451 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F.</p><p>\u0418\u0434\u0435\u0438 \u0414. \u0411\u043E\u0439\u0434\u0430 \u0441\u043B\u043E\u0436\u0438\u043B\u0438\u0441\u044C \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u0442\u0440\u0443\u0434\u043E\u0432 \u0442\u0430\u043A\u0438\u0445 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0445 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439 \u043A\u0430\u043A: \u0416\u0430\u043D \u041F\u0438\u0430\u0436\u0435, \u041B\u044E\u0434\u0432\u0438\u0433 \u0444\u043E\u043D \u0411\u0435\u0440\u0442\u0430\u043B\u0430\u043D\u0444\u0438, \u0422\u043E\u043C\u0430\u0441 \u041A\u0443\u043D, \u041C\u0430\u0439\u043A\u043B \u041F\u043E\u043B\u0430\u043D\u0438, \u041D\u043E\u0440\u0431\u0435\u0440\u0442 \u0412\u0438\u043D\u0435\u0440, \u0413\u0440\u0435\u0433\u043E\u0440\u0438 \u0411\u044D\u0439\u0442\u0441\u043E\u043D.</p><h3 id="\u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F-\u043D\u043E\u0440\u0434" tabindex="-1">\u041A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F \u041D\u041E\u0420\u0414 <a class="header-anchor" href="#\u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044F-\u043D\u043E\u0440\u0434" aria-hidden="true">#</a></h3><p>\u0421\u0432\u043E\u044E \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u044E \u0414. \u0411\u043E\u0439\u0434 \u0440\u0430\u0437\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u043B \u0434\u043B\u044F \u0430\u0440\u043C\u0438\u0438 \u0421\u0428\u0410. \u0412 \u0441\u0432\u044F\u0437\u0438 \u0441 \u044D\u0442\u0438\u043C \u041D\u041E\u0420\u0414 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0441\u0442\u0430\u0432\u0438\u043B \u0441\u0432\u043E\u0435\u0439 \u0437\u0430\u0434\u0430\u0447\u0435\u0439 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u0447\u0438\u043D \u043F\u043E\u0440\u0430\u0436\u0435\u043D\u0438\u0439 \u0438 \u043F\u043E\u0431\u0435\u0434 \u043C\u0435\u0436\u0434\u0443 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A\u0430\u043C\u0438. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438 \u0414. \u0411\u043E\u0439\u0434\u0430, \u043E\u0431\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, \u0432\u0441\u0442\u0443\u043F\u0430\u044E\u0449\u0438\u0435 \u0432 \u0432\u043E\u0435\u043D\u043D\u044B\u0439 \u043A\u043E\u043D\u0444\u043B\u0438\u043A\u0442, \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u0438 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u0432 \u0440\u0430\u043C\u043A\u0430\u0445 \u0441\u0432\u043E\u0435\u0439 \u043F\u0435\u0442\u043B\u0438 \u041D\u041E\u0420\u0414.</p><p>\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0434\u0432\u0430 \u043E\u0441\u043D\u043E\u0432\u043D\u044B\u0445 \u0441\u043F\u043E\u0441\u043E\u0431\u0430 \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u043F\u043E\u0431\u0435\u0434\u044B \u043D\u0430\u0434 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A\u043E\u043C: \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u0432\u043E\u0438 \u0446\u0438\u043A\u043B\u044B \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u0431\u043E\u043B\u0435\u0435 \u0431\u044B\u0441\u0442\u0440\u044B\u043C\u0438 \u0438\u043B\u0438 \u0443\u043B\u0443\u0447\u0448\u0438\u0442\u044C \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439. \u041F\u0435\u0440\u0432\u044B\u0439 \u0432\u0430\u0440\u0438\u0430\u043D\u0442 \u043F\u043E\u0437\u0432\u043E\u043B\u0438\u0442 \u0434\u0435\u0439\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u043E\u043F\u0435\u0440\u0435\u0436\u0435\u043D\u0438\u0435 \u0438 \u0432\u044B\u043D\u0443\u0434\u0438\u0442 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A\u0430 \u0440\u0435\u0430\u0433\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F (\u0431\u043E\u043B\u0435\u0435 \u0431\u044B\u0441\u0442\u0440\u0430\u044F \u043F\u0435\u0442\u043B\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u0447\u0435\u043C \u0443 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A\u0430). \u0412\u0442\u043E\u0440\u043E\u0439 \u043F\u0443\u0442\u044C \u2014 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0439, \u043B\u0443\u0447\u0448\u0435 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 \u0434\u0430\u043D\u043D\u043E\u0439 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438, \u0447\u0435\u043C \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A\u0430 \u0438\u043B\u0438 \u0436\u0435 \u0434\u043E\u0431\u0438\u0442\u044C\u0441\u044F \u0443\u0445\u0443\u0434\u0448\u0435\u043D\u0438\u044F \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0441\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u044B \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A\u0430. \u0412\u043E \u043C\u043D\u043E\u0433\u0438\u0445 \u0441\u043B\u0443\u0447\u0430\u044F\u0445 \u043F\u0440\u043E\u0442\u0438\u0432\u043D\u0438\u043A \u043C\u043E\u0436\u0435\u0442 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C, \u0432 \u0442\u0430\u043A\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u0435\u0433\u043E \u0437\u0430\u043C\u0435\u043D\u044F\u0435\u0442 \u0432\u043D\u0435\u0448\u043D\u044F\u044F \u0441\u0440\u0435\u0434\u0430.</p><h3 id="_4-\u044Dn\u0435\u043C\u0435\u043D\u0442\u0430-\u043D\u043E\u0440\u0434" tabindex="-1">4 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430 \u041D\u041E\u0420\u0414 <a class="header-anchor" href="#_4-\u044Dn\u0435\u043C\u0435\u043D\u0442\u0430-\u043D\u043E\u0440\u0434" aria-hidden="true">#</a></h3><ul><li><strong>\u041D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u0435</strong> (\u0430\u043D\u0433\u043B. Observation) \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043F\u0440\u0435\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 \u0432\u043E \u0432\u043D\u0435\u0448\u043D\u0435\u0439 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 (\u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u0439 \u0441\u0432\u044F\u0437\u0438) \u0441\u0440\u0435\u0434\u0435 \u0432 \u0444\u043E\u0440\u043C\u0443 \u0441\u0438\u0433\u043D\u0430\u043B\u043E\u0432-\u0434\u0430\u043D\u043D\u044B\u0445, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0449\u0438\u0445\u0441\u044F \u0432 \u0434\u0430\u043B\u044C\u043D\u0435\u0439\u0448\u0435\u043C. \u0418\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E \u043C\u043E\u0436\u043D\u043E \u0441\u043E\u0431\u0438\u0440\u0430\u0442\u044C \u0438\u0437 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0438 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432. \u041A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \u0438 \u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C \u0441\u0431\u043E\u0440\u0430 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044E\u0442 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439.</li><li><strong>\u041E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u044F</strong> (\u0430\u043D\u0433\u043B. Orientation) \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u043E\u0446\u0435\u043D\u043A\u0438 \u0434\u0430\u043D\u043D\u044B\u0445 \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u043E\u043C, \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0434\u0430\u043D\u043D\u044B\u0445 \u0441\u043C\u044B\u0441\u043B\u043E\u043C. \u0421\u043A\u043E\u0440\u043E\u0441\u0442\u044C \u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \u044D\u0442\u043E\u0433\u043E \u044D\u0442\u0430\u043F\u0430 \u0437\u0430\u0432\u0438\u0441\u044F\u0442 \u043E\u0442 \u0442\u043E\u0433\u043E, \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0443\u0436\u0435 \u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u043F\u043B\u0430\u043D\u043E\u0432. \u0415\u0441\u043B\u0438 \u0438\u0445 \u043C\u0430\u043B\u043E \u0438\u043B\u0438 \u043D\u0435\u0442, \u0442\u043E \u0431\u0443\u0434\u0435\u0442 \u0437\u0430\u0442\u0440\u0430\u0447\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u0432\u0440\u0435\u043C\u044F \u043D\u0430 \u0438\u0445 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0443. \u041E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u044F \u2014 \u0441\u0430\u043C\u044B\u0439 \u0441\u043B\u043E\u0436\u043D\u044B\u0439 \u044D\u0442\u0430\u043F \u0432\u043E \u0432\u0441\u0435\u043C \u0446\u0438\u043A\u043B\u0435. \u0414\u0430\u043D\u043D\u044B\u0439 \u044D\u0442\u0430\u043F \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0434\u0432\u0443\u0445 \u043F\u043E\u0434\u044D\u0442\u0430\u043F\u043E\u0432: <ul><li>\u0410. <strong>\u0420\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435</strong> (\u0430\u043D\u0433\u043B. Destruction). \u0420\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u043C \u0440\u0430\u0437\u0434\u0440\u043E\u0431\u043B\u0435\u043D\u0438\u044F \u043D\u0430 \u043C\u0435\u043B\u043A\u0438\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u0440\u043D\u044B\u0435 \u0447\u0430\u0441\u0442\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u043E\u043B\u0435\u0435 \u043B\u0435\u0433\u043A\u0438 \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F.</li><li>\u0411. <strong>\u0421\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u0435</strong> (\u0430\u043D\u0433\u043B. Creation). \u0415\u0441\u043B\u0438 \u043F\u043E\u0434\u044D\u0442\u0430\u043F \xAB\u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435\xBB \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442 \u0434\u0435\u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u044E \u0441\u043B\u043E\u0436\u043D\u043E\u0433\u043E \u0432\u043E\u043F\u0440\u043E\u0441\u0430, \u0442\u043E \xAB\u043F\u043E\u0434\u044D\u0442\u0430\u043F\xBB \u0441\u043E\u0437\u0438\u0434\u0430\u043D\u0438\u0435 \u0441\u0442\u0430\u0432\u0438\u0442 \u0441\u0432\u043E\u0435\u0439 \u0446\u0435\u043B\u044C\u044E, \u0437\u0430 \u0441\u0447\u0435\u0442 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0443\u043F\u0440\u043E\u0449\u0435\u043D\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438, \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u043F\u043B\u0430\u043D\u0430 \u0438 \u0430\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432 \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B.</li></ul></li><li><strong>\u0420\u0435\u0448\u0435\u043D\u0438\u0435</strong> (\u0430\u043D\u0433\u043B. Decision) \u2014 \u044D\u0442\u0430\u043F, \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u044E\u0449\u0438\u0439 \u0432\u044B\u0431\u043E\u0440 \u0430\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432 \u0438 \u043F\u043B\u0430\u043D\u043E\u0432 \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u0430 \u043D\u0430 \u044D\u0442\u0430\u043F\u0435 \u043E\u0440\u0438\u0435\u043D\u0442\u0430\u0446\u0438\u0438. \u041A\u0440\u0438\u0442\u0435\u0440\u0438\u0438 \u0432\u044B\u0431\u043E\u0440\u0430 \u043C\u043E\u0433\u0443\u0442 \u0431\u044B\u0442\u044C \u0440\u0430\u0437\u043D\u044B\u043C\u0438 \u0438 \u0437\u0430\u0432\u0438\u0441\u0435\u0442\u044C \u043E\u0442 \u0446\u0435\u043B\u0435\u0439 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u0441\u0438\u0441\u0442\u0435\u043C\u044B;</li><li><strong>\u0414\u0435\u0439\u0441\u0442\u0432\u0438\u0435</strong> (\u0430\u043D\u0433\u043B. Action) \u2014 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u043D\u0430 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0443\u044E \u0441\u0440\u0435\u0434\u0443. \u041F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0433\u043E \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u043B\u0430\u043D\u0430. \u0412 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u043D\u0430 \u044D\u0442\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0432\u043D\u0435\u0448\u043D\u044F\u044F \u0441\u0440\u0435\u0434\u0430 \u0438\u0437\u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F, \u0447\u0442\u043E \u0441\u043D\u043E\u0432\u0430 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u0432\u0441\u044E \u0441\u0438\u0441\u0442\u0435\u043C\u0443. \u0420\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u043D\u0446\u0438\u043F \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u0439 \u0441\u0432\u044F\u0437\u0438.</li></ul><h3 id="\u0446\u0438\u043An-\u043D\u043E\u0440\u0434-\u0432-\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0435" tabindex="-1">\u0426\u0438\u043A\u043B \u041D\u041E\u0420\u0414 \u0432 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0435 <a class="header-anchor" href="#\u0446\u0438\u043An-\u043D\u043E\u0440\u0434-\u0432-\u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0435" aria-hidden="true">#</a></h3><p>\u0412 \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0438 \u043A \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u043C \u043F\u0440\u043E\u0435\u043A\u0442\u0430\u043C \u043C\u044B \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0441\u043C\u0435\u0449\u0430\u0435\u043C \u0430\u043A\u0446\u0435\u043D\u0442\u044B \u043E\u0442 \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u044F \u0432\u043D\u0435\u0448\u043D\u0435\u0439 \u043E\u0431\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0438 \u043A \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u0438\u044E \u0438\u043C\u0435\u044E\u0449\u0438\u0445\u0441\u044F \u0434\u0430\u043D\u043D\u044B\u0445 \u0441\u043C\u044B\u0441\u043B\u043E\u043C. \u041D\u0435 \u0441\u0442\u043E\u043B\u044C \u0432\u0430\u0436\u043D\u043E, \u0441 \u0447\u0435\u0433\u043E \u043D\u0430\u0447\u0438\u043D\u0430\u0442\u044C \u044D\u0442\u043E\u0442 \u043D\u0435\u0441\u043B\u043E\u0436\u043D\u044B\u0439 \u043E\u0442\u0441\u0447\u0435\u0442, \u043D\u043E \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u043C\u044B \u0435\u0449\u0435 \u0438 \u0430\u043A\u0446\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u043C \u0432\u0430\u0436\u043D\u043E\u0441\u0442\u044C \u043D\u0430\u0431\u043B\u044E\u0434\u0435\u043D\u0438\u044F \u0438\u043C\u0435\u043D\u043D\u043E \u0438\u0442\u043E\u0433\u043E\u0432\u044B\u0445 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0430\u043A\u0442\u0430 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 \u043E\u0431\u0441\u0442\u0430\u043D\u043E\u0432\u043A\u0435. \u041C\u044B \u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u043C \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u043C \u0438\u0445 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u043C \u0438 \u0432\u043C\u0435\u0441\u0442\u0435 \u043E\u0442\u043C\u0435\u0447\u0430\u0435\u043C \u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0435 \u043E\u0447\u0435\u0440\u0435\u0434\u043D\u043E\u0433\u043E \u0446\u0438\u043A\u043B\u0430. \u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E - \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u044D\u0442\u043E \u0437\u043D\u0430\u0447\u0438\u0442, \u0447\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0446\u0438\u043A\u043B \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0438\u043C\u0435\u043D\u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u0435\u0441\u0442\u044C \u043E\u0431\u0430 \u0438\u043D\u0433\u0440\u0435\u0434\u0438\u0435\u043D\u0442\u0430 \u2013 \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043E \u0442\u043E\u043C, \u043A\u0430\u043A \u0435\u0451 \u043C\u043E\u0436\u043D\u043E \u0443\u043B\u0443\u0447\u0448\u0438\u0442\u044C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0443\u0441\u0438\u043B\u0438\u044F\u043C\u0438.</p><p>\u0412 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u043F\u043E\u0434\u0445\u043E\u0434 \u041D\u041E\u0420\u0414 \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D \u043D\u0430 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u0445 \u0437\u0430\u0434\u0430\u043D\u043D\u044B\u0445 \u043A\u0440\u0438\u0442\u0435\u0440\u0438\u0435\u0432 \u0443\u0441\u043F\u0435\u0445\u0430 \u0438 \u0434\u0435\u0442\u0435\u0440\u043C\u0438\u043D\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0432\u043D\u0435\u0448\u043D\u0438\u043C\u0438 \u043E\u0431\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u043C\u0438, \u0446\u0438\u043A\u043B \u0424\u0430\u043D\u0442\u0430\u0437\u0438\u0438, \u0420\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438, \u0420\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u041E\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u0438\u044F \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0438\u043C \u0447\u0443\u0432\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u0433\u043E \u0438\u0437\u043D\u0443\u0442\u0440\u0438. \u042D\u0442\u043E \u043D\u0438\u043A\u0430\u043A \u043D\u0435 \u043E\u0442\u043C\u0435\u043D\u044F\u0435\u0442 \u0432\u043A\u043B\u044E\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0430\u043A\u0442\u0430, \u043D\u043E \u0440\u0430\u0441\u0448\u0438\u0440\u044F\u0435\u0442 \u0433\u0440\u0430\u043D\u0438\u0446\u044B \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0433\u043E, \u0437\u0430 \u0441\u0447\u0435\u0442 \u0431\u043E\u043B\u044C\u0448\u0435\u0439 \u0441\u0432\u043E\u0431\u043E\u0434\u044B \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u044F \u0443\u0441\u0438\u043B\u0438\u0439.</p>',13),o=[i];function s(l,d,c,h,p,_){return r(),t("div",null,o)}var f=e(n,[["render",s]]);export{g as __pageData,f as default};
